SELECT COUNT(*) 
FROM developments 
WHERE development_status = 'in progress';

SELECT stakeholder_type, COUNT(stakeholder_uri) AS stakeholder_count
FROM stakeholders
GROUP BY stakeholder_type;

SELECT site_reference, development_description
FROM developments
WHERE development_status = 'in progress';

SELECT development_status, COUNT(site_reference) AS number_of_sites
FROM developments
GROUP BY development_status;

SELECT site_reference, COUNT(DISTINCT organisation_uri) AS organisation_count
FROM sites
GROUP BY site_reference;

SELECT stakeholder_name, stakeholder_type
FROM stakeholders
WHERE stakeholder_uri = '1';
